5	const DOCS_QUERY = gql`
6		query Documents($first: Int, $after: String) {
7			documents(first: $first, after: $after) {
8				edges {
9					node {
10						id
11						path
12						title
13					}
14					cursor
15				}
16				pageInfo {
17					hasNextPage
18					endCursor
19				}
20				totalCount
21			}
22		}
23	`
24	
25	interface DocumentNode {
26		id: string
27		path: string
28		title: string
29	}
30	
31	interface DocumentEdge {
32		node: DocumentNode
33		cursor: string
34	}
35	
36	interface PageInfo {
37		hasNextPage: boolean
38		endCursor: string | null
39	}
40	
41	interface DocumentConnection {
42		edges: DocumentEdge[]
43		pageInfo: PageInfo
44		totalCount: number
45	}
46	
47	interface DocsResult {
48		documents: DocumentConnection
49	}
50	
51	export const load: PageLoad = async ({ fetch }) => {
52		const client = createClient(fetch as unknown as typeof globalThis.fetch)
53		const data = await client.request<DocsResult>(DOCS_QUERY, { first: 200 })
54		return {
55			docs: data.documents
56		}
57	}
