72	
73			function textOf(node: Node) {
74				return (node.textContent ?? '').replace(/ /g, ' ').trim();
75			}
76	
77			function addBlock(value: string) {
78				const normalized = normalizeMarkdownBody(value);
79				if (normalized) blocks.push(normalized);
80			}
81	
82			for (const child of Array.from(root.childNodes)) {
