39	// Artifacts is the resolver for the artifacts query.
40	// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
41	// for the given project. Documents come from the FEAT-007 doc graph; other
42	// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
43	func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string) (*ArtifactConnection, error) {
44		root := r.projectRoot(projectID)
45	
46		artifacts, err := collectArtifacts(root)
47		if err != nil {
48			return nil, fmt.Errorf("collecting artifacts: %w", err)
49		}
50	
51		// Sort by path for stable ordering.
52		sort.Slice(artifacts, func(i, j int) bool {
53			return artifacts[i].Path < artifacts[j].Path
54		})
55	
56		// Apply mediaType filter.
57		if mediaType != nil && *mediaType != "" {
58			mt := *mediaType
59			filtered := artifacts[:0]
60			for _, a := range artifacts {
61				if a.MediaType == mt {
62					filtered = append(filtered, a)
63				}
64			}
65			artifacts = filtered
66		}
67	
68		// Apply search filter across title and path.
69		if search != nil && *search != "" {
70			q := strings.ToLower(*search)
71			filtered := artifacts[:0]
72			for _, a := range artifacts {
73				if strings.Contains(strings.ToLower(a.Title), q) ||
74					strings.Contains(strings.ToLower(a.Path), q) {
75					filtered = append(filtered, a)
76				}
77			}
78			artifacts = filtered
79		}
80	
81		// Build Relay edges.
82		all := make([]*ArtifactEdge, len(artifacts))
83		for i, a := range artifacts {
84			cp := a
85			all[i] = &ArtifactEdge{
86				Node:   cp,
87				Cursor: encodeStableCursor(cp.ID),
88			}
89		}
90	
91		startIdx := 0
92		if after != nil {
93			if afterID, ok := decodeStableCursor(*after); ok {
94				for i, e := range all {
95					if e.Node.ID == afterID {
96						startIdx = i + 1
97						break
98					}
99				}
100			}
101		}
102		endIdx := len(all)
103		if before != nil {
104			if beforeID, ok := decodeStableCursor(*before); ok {
105				for i, e := range all {
106					if e.Node.ID == beforeID {
107						endIdx = i
108						break
109					}
110				}
111			}
112		}
113		if startIdx > endIdx {
114			startIdx = endIdx
115		}
116	
117		windowSize := endIdx - startIdx
118		slice := all[startIdx:endIdx]
119		if first != nil && *first >= 0 && *first < len(slice) {
120			slice = slice[:*first]
121		}
122		if last != nil && *last >= 0 && *last < len(slice) {
123			slice = slice[len(slice)-*last:]
124		}
125	
126		pageInfo := &PageInfo{
127			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
128			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
129		}
130		if len(slice) > 0 {
131			pageInfo.StartCursor = &slice[0].Cursor
132			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
133		}
134	
135		return &ArtifactConnection{
136			Edges:      slice,
137			PageInfo:   pageInfo,
138			TotalCount: len(all),
139		}, nil
140	}
141	
142	// collectArtifacts gathers all DDx-tracked artifacts from two sources:
143	//  1. The doc graph (markdown documents under the project root).
144	//  2. .ddx.yaml sidecar files under .ddx/plugins/.
145	func collectArtifacts(root string) ([]*Artifact, error) {
146		var artifacts []*Artifact
147	
148		// 1. Documents from the doc graph.
149		if docs, err := collectDocArtifacts(root); err == nil {
150			artifacts = append(artifacts, docs...)
151		}
152	
153		// 2. Sidecar artifacts from .ddx/plugins/.
154		if sidecars, err := collectSidecarArtifacts(root); err == nil {
155			artifacts = append(artifacts, sidecars...)
156		}
157	
158		return artifacts, nil
159	}
160	
161	// collectDocArtifacts builds Artifact records from the FEAT-007 doc graph.
162	func collectDocArtifacts(root string) ([]*Artifact, error) {
163		graph, err := docgraph.BuildGraphWithConfig(root)
164		if err != nil {
165			return nil, err
166		}
167	
168		staleSet := map[string]string{} // id → staleness ("stale" or "missing")
169		for _, entry := range graph.StaleDocs() {
170			staleness := "stale"
171			for _, reason := range entry.Reasons {
172				if strings.Contains(reason, "missing dependency") ||
173					strings.Contains(reason, "missing review hash") {
174					staleness = "missing"
175					break
176				}
177			}
178			staleSet[entry.ID] = staleness
179		}
180	
181		docs := graph.AllNodesForOutput()
182		out := make([]*Artifact, 0, len(docs))
183		for _, d := range docs {
184			staleness := "fresh"
185			if s, ok := staleSet[d.ID]; ok {
186				staleness = s
187			}
188	
189			a := &Artifact{
190				ID:        "doc:" + d.ID,
191				Path:      d.Path,
192				Title:     titleFromDoc(d),
193				MediaType: "text/markdown",
194				Staleness: staleness,
195			}
196	
197			// Populate updatedAt from file mod time.
198			absPath := d.Path
199			if !filepath.IsAbs(absPath) {
200				absPath = filepath.Join(graph.RootDir, absPath)
201			}
202			if info, statErr := os.Stat(absPath); statErr == nil {
203				ts := info.ModTime().UTC().Format(time.RFC3339)
204				a.UpdatedAt = &ts
205			}
206	
207			// Populate ddxFrontmatter as a JSON summary of available metadata.
208			frontmatter := map[string]interface{}{
209				"id": d.ID,
210			}
211			if len(d.DependsOn) > 0 {
212				frontmatter["depends_on"] = d.DependsOn
213			}
214			if d.Prompt != "" {
215				frontmatter["prompt"] = d.Prompt
216			}
217			if fm, err := json.Marshal(frontmatter); err == nil {
218				s := string(fm)
219				a.DdxFrontmatter = &s
220			}
221	
222			out = append(out, a)
223		}
224		return out, nil
225	}
226	
227	// collectSidecarArtifacts walks .ddx/plugins/ looking for *.ddx.yaml sidecar
228	// files, then builds an Artifact for each corresponding artifact file.
229	// Files whose sidecar is missing or unreadable are silently skipped.
230	func collectSidecarArtifacts(root string) ([]*Artifact, error) {
231		pluginsDir := filepath.Join(root, ".ddx", "plugins")
232		if _, err := os.Stat(pluginsDir); os.IsNotExist(err) {
233			return nil, nil
234		}
235	
236		var out []*Artifact
237		err := filepath.WalkDir(pluginsDir, func(path string, d fs.DirEntry, err error) error {
238			if err != nil || d.IsDir() {
239				return nil
240			}
241			if !strings.HasSuffix(path, ".ddx.yaml") {
242				return nil
243			}
244	
245			// Derive artifact path by stripping the .ddx.yaml suffix.
246			artifactPath := strings.TrimSuffix(path, ".ddx.yaml")
247	
248			// Parse the sidecar.
249			data, readErr := os.ReadFile(path)
250			if readErr != nil {
251				return nil // skip unreadable sidecars
252			}
253			var sidecar ddxSidecarFile
254			if yamlErr := yaml.Unmarshal(data, &sidecar); yamlErr != nil {
255				return nil // skip malformed sidecars
256			}
257	
258			rel, relErr := filepath.Rel(root, artifactPath)
259			if relErr != nil {
260				rel = artifactPath
261			}
262	
263			id := sidecar.DDx.ID
264			if id == "" {
265				id = "sidecar:" + rel
266			}
267	
268			title := sidecar.DDx.Title
269			if title == "" {
270				title = filepath.Base(artifactPath)
271			}
272	
273			mediaType := sidecar.DDx.MediaType
274			if mediaType == "" {
275				mediaType = "application/octet-stream"
276			}
277	
278			staleness := computeSidecarStaleness(artifactPath, sidecar.DDx.GeneratedBy)
279	
280			a := &Artifact{
281				ID:        id,
282				Path:      filepath.ToSlash(rel),
283				Title:     title,
284				MediaType: mediaType,
285				Staleness: staleness,
286			}
287	
288			if sidecar.DDx.Description != "" {
289				desc := sidecar.DDx.Description
290				a.Description = &desc
291			}
292	
293			if sidecar.DDx.GeneratedBy != nil {
294				gb := sidecar.DDx.GeneratedBy
295				sourceHashMatch := false
296				if gb.SourceHash != "" {
297					if hash, hashErr := fileSHA256(artifactPath); hashErr == nil {
298						sourceHashMatch = (hash == gb.SourceHash)
299					}
300				}
301				a.GeneratedBy = &ArtifactGeneratedBy{
302					RunID:           gb.RunID,
303					PromptSummary:   gb.PromptSummary,
304					SourceHashMatch: sourceHashMatch,
305				}
306			}
307	
308			// Populate ddxFrontmatter from the raw sidecar ddx block.
309			if fm, marshalErr := json.Marshal(sidecar.DDx); marshalErr == nil {
310				s := string(fm)
311				a.DdxFrontmatter = &s
312			}
313	
314			// Populate updatedAt from artifact file mod time.
315			if info, statErr := os.Stat(artifactPath); statErr == nil {
316				ts := info.ModTime().UTC().Format(time.RFC3339)
317				a.UpdatedAt = &ts
318			}
319	
320			out = append(out, a)
321			return nil
322		})
323		if err != nil {
324			return nil, err
325		}
326		return out, nil
327	}
328	
329	// computeSidecarStaleness returns the staleness of a sidecar artifact.
330	func computeSidecarStaleness(artifactPath string, gb *ddxGeneratedBy) string {
331		if _, err := os.Stat(artifactPath); os.IsNotExist(err) {
332			return "missing"
333		}
334		if gb == nil || gb.SourceHash == "" {
335			return "fresh"
336		}
337		hash, err := fileSHA256(artifactPath)
338		if err != nil {
339			return "fresh" // can't determine staleness without a hash
340		}
341		if hash == gb.SourceHash {
342			return "fresh"
343		}
344		return "stale"
345	}
346	
347	// fileSHA256 returns the hex-encoded SHA-256 hash of a file's contents.
348	func fileSHA256(path string) (string, error) {
349		data, err := os.ReadFile(path)
350		if err != nil {
351			return "", err
352		}
353		h := sha256.Sum256(data)
354		return hex.EncodeToString(h[:]), nil
355	}
356	
357	// titleFromDoc derives a human-readable title from a docgraph document.
358	// Uses the Title field if set, otherwise derives from the path's base name.
359	func titleFromDoc(d docgraph.Document) string {
360		if d.Title != "" {
361			return d.Title
362		}
363		base := filepath.Base(d.Path)
364		// Strip extension.
365		if idx := strings.LastIndex(base, "."); idx > 0 {
366			base = base[:idx]
367		}
368		return base
369	}
