import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

export const ARTIFACTS_QUERY = gql`
	query Artifacts($projectID: ID!, $first: Int, $after: String, $mediaType: String) {
		artifacts(projectID: $projectID, first: $first, after: $after, mediaType: $mediaType) {
			edges {
				node {
					id
					path
					title
					mediaType
					staleness
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

export interface ArtifactNode {
	id: string
	path: string
	title: string
	mediaType: string
	staleness: string
}

export interface ArtifactEdge {
	node: ArtifactNode
	cursor: string
}

export interface PageInfo {
	hasNextPage: boolean
	endCursor: string | null
}

export interface ArtifactConnection {
	edges: ArtifactEdge[]
	pageInfo: PageInfo
	totalCount: number
}

interface ArtifactsResult {
	artifacts: ArtifactConnection
}

export const PAGE_SIZE = 50

export const load: PageLoad = async ({ params, url, fetch }) => {
	const mediaType = url.searchParams.get('mediaType') ?? null
	const q = url.searchParams.get('q') ?? ''

	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
		projectID: params.projectId,
		first: PAGE_SIZE,
		mediaType: mediaType ?? undefined
	})
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifacts: data.artifacts,
		mediaType,
		q
	}
}

import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const ARTIFACT_NODE_QUERY = gql`
	query ArtifactNode($id: ID!) {
		node(id: $id) {
			... on Artifact {
				id
				path
				title
				mediaType
				staleness
				description
				updatedAt
			}
		}
	}
`

interface ArtifactDetail {
	id: string
	path: string
	title: string
	mediaType: string
	staleness: string
	description: string | null
	updatedAt: string | null
}

interface ArtifactNodeResult {
	node: ArtifactDetail | null
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<ArtifactNodeResult>(ARTIFACT_NODE_QUERY, {
		id: params.artifactId
	})
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifactId: params.artifactId,
		artifact: data.node
	}
}

